from source import gcd

def test_gcd_infinite_recursion():
    a, b = 35, 21
    expected = 7
    try:
        result = gcd(a, b)
        assert result == expected, f"Expected the gcd of {a} and {b} to be {expected}, but got {result}"
    except RecursionError:
        pass  # Expected failure due to infinite recursion
    else:
        assert False, "Expected a RecursionError due to infinite recursion, but the call did not raise any exception"
